INSERT INTO prescription_examples (student_key, student_profile, workouts, workout_split) VALUES ('helen_tiene', '{"name":"Helen Tiene","mapped_name":null,"birth_date":"1987-06-16","profession":"Vendas","sports_history":"Gosto de atividades em equipe. Já joguei handebol na adolescência, hoje pratico somente Crossfit e yoga 1x na semana. Não sou muito fã de academia, mas entendo que preciso realizar fortalecimento.","injuries":["Crônicas não tenho nenhuma. Mas estou com dores no ombro direito."],"health_conditions":["Tenho escoliose na lombar","mas por ser uma lesão mínima","não interfere e não sinto dores."],"medications":["Nao"],"current_practice":"Posso dizer que realizo mesmo atividades (+3x na semana) por volta de 10 anos. Já fiz planilha de corrida nesse tempo, TRX, funcional, Crossfit e yoga.","goal":"Fortalecimento muscular e Estetica.","weekly_frequency":3,"session_duration":null,"gender":"F","experience_level":"intermediário","form_timestamp":"2023/03/29 1:06:56 PM GMT-3"}'::jsonb, '{"A":{"focus":"","exercises":[{"name":"Agachamento Rack","method":"Tradicional","sets":2,"interval":"1''30\" - 2''"},{"name":"Cadeira Extensora","method":"Tradicional","sets":2,"interval":"1''30\" - 2''"},{"name":"Cadeira Abdutora","method":"Tradicional","sets":2,"reps":"15-20","interval":"1''"},{"name":"Panturrilha Banco","method":"Tradicional","sets":2,"reps":"10+10","interval":"1''"}]},"B":{"focus":"","exercises":[{"name":"Crucifixo Inverso Máquina Pegada Neutra","method":"Tradicional","sets":1,"reps":"15.0","interval":"1''30\""},{"name":"Extensão da Coluna no Banco Romano","method":"Tradicional","sets":1,"weight":"Peso Corporal (progredir)","interval":"1''"},{"name":"Remada Baixa Máquina Divergente/Tradicional","method":"Tradicional","sets":2,"interval":"1''30\""},{"name":"Bíceps 45°","method":"Tradicional","sets":2,"interval":"1''"}]},"C":{"focus":"","exercises":[{"name":"Step Up com Caneleiras","method":"Tradicional","sets":1,"interval":"1''","observations":"Usar um caixote/banco alto"},{"name":"Hiperextensão de Quadril na Polia Baixa","method":"Tradicional","sets":1,"reps":"15-15","interval":"1''30\""},{"name":"Glúteo Coice","method":"Tradicional","sets":1,"interval":"1''30\""},{"name":"Mesa Flexora","method":"DropSet","sets":2,"reps":"8+8","interval":"1''","observations":"Dropar 1 bloco e fazer as ultimas 8 reps"},{"name":"Panturrilha Joelho Estendido","method":"Tradicional","sets":1,"reps":"15.0","weight":"15kg cada lado","interval":"1''"}]},"D":{"focus":"","exercises":[{"name":"Supino Inclinado Barra","method":"Tradicional","sets":1,"interval":"1''30\""},{"name":"Elevação Frontal + Elevação Lateral","method":"BiSet","sets":1,"reps":"10+10","weight":"5/3kg","interval":"1''"},{"name":"Crucifixo Inverso Máquina (Pegada Pronada)","method":"Tradicional","sets":1,"reps":"10+10","interval":"1''30\""},{"name":"Tríceps Barra Polia Alta","method":"Tradicional","sets":1,"reps":"10-14","interval":"1''30\""}]},"E":{"focus":"","exercises":[]}}'::jsonb, ARRAY['A','B','C','D']::TEXT[]) ON CONFLICT (student_key) DO UPDATE SET student_profile = EXCLUDED.student_profile, workouts = EXCLUDED.workouts, workout_split = EXCLUDED.workout_split;